#include <vector>
#include <string>

struct Record { std::string dept; double salary; };

double get_dept_total(const std::vector<Record>& records, const std::string& target_dept) {
    double total = 0.0;
    for(const auto& r : records) {
        if(r.dept == target_dept) total += r.salary;
    }
    return total;
}

examples.toCode:
SELECT SUM(salary) AS total_salary 
FROM records 
WHERE dept = :target_dept;

